import scala.xml.XML
import scala.xml.Node
import scala.util.Try

trait ConfigParser {
  def parseConfig(xmlString: String): Try[Node]
  def extractSettings(config: Node): Map[String, String]
}

class XmlConfigParser extends ConfigParser {
  override def parseConfig(xmlString: String): Try[Node] = {
    Try {
      XML.loadString(xmlString)
    }
  }

  override def extractSettings(config: Node): Map[String, String] = {
    val settings = scala.collection.mutable.Map[String, String]()
    
    def processNode(node: Node): Unit = {
      node.child.foreach { child =>
        child match {
          case elem: scala.xml.Elem =>
            if (elem.label == "setting") {
              val key = elem.attribute("name").map(_.text).getOrElse("")
              val value = elem.text
              if (key.nonEmpty) {
                settings(key) = value
              }
            } else {
              processNode(child)
            }
          case _ => processNode(child)
        }
      }
    }
    
    processNode(config)
    settings.toMap
  }
}

class ConfigService(parser: ConfigParser) {
  def loadAndParseConfig(xmlString: String): Try[Map[String, String]] = {
    for {
      parsedConfig <- parser.parseConfig(xmlString)
      settings <- Try(parser.extractSettings(parsedConfig))
    } yield settings
  }
}